public:
    static int& get() { return value_; }
private:
    static int value_;
};
int Singleton::value_ = 0;

int main() {
    int i = Singleton::get();
    ++Singleton::get();
    std::cout << "Valor de la variable singleton: " << Singleton::get() << std::endl;
    return 0;
}
```

